// Lead scoring: follower bell-curve (max 30) + engagement (max 30) + bio relevance (max 40) + geo bonus (+5)
const items = $input.all();
const GEO = ['us','usa','united states','uk','london','canada','australia','india','new york','san francisco','los angeles','toronto','mumbai','bangalore','dubai','singapore','berlin','amsterdam'];
const T1 = ['ai','automation','agency','saas'];
const T2 = ['marketing','growth','tech','startup','consultant','founder','ceo','chatgpt','gpt','openai','n8n','zapier'];
const T3 = ['digital','freelance','business','entrepreneur','coach','strategist'];

return items.map(item => {
  const d = item.json;
  const fc = d.ownerFollowerCount || d.followersCount || 0;
  const er = fc > 0 ? ((d.likesCount || 0) + (d.commentsCount || 0)) / fc : 0;
  const bio = (d.biography || d.bio || '').toLowerCase();
  const loc = (d.locationName || d.location || bio).toLowerCase();

  let fs = 0;
  if (fc >= 500 && fc < 1000) fs = 10;
  else if (fc >= 1000 && fc < 5000) fs = 22;
  else if (fc >= 5000 && fc < 20000) fs = 30;
  else if (fc >= 20000 && fc < 50000) fs = 25;
  else if (fc >= 50000 && fc <= 100000) fs = 15;

  const es = Math.min(Math.round(er * 1000), 30);
  const bs = Math.min(
    T1.filter(k => bio.includes(k)).length * 10 +
    T2.filter(k => bio.includes(k)).length * 5 +
    T3.filter(k => bio.includes(k)).length * 3,
    40
  );
  const geo = GEO.some(g => loc.includes(g));
  const score = Math.min(fs + es + bs + (geo ? 5 : 0), 100);

  return {
    json: {
      platform: 'instagram',
      username: d.ownerUsername || d.username || '',
      displayName: d.fullName || d.ownerFullName || '',
      bio: d.biography || d.bio || '',
      followerCount: fc,
      engagementRate: parseFloat(er.toFixed(4)),
      leadScore: score,
      profileUrl: 'https://instagram.com/' + (d.ownerUsername || d.username),
      postCaption: (d.caption || '').substring(0, 200),
      location: d.locationName || '',
      scrapedAt: new Date().toISOString(),
      geoMatch: geo ? 'yes' : 'no',
      status: 'new'
    }
  };
}).filter(i =>
  i.json.username &&
  i.json.followerCount >= 0 &&
  i.json.followerCount <= 100000 &&
  i.json.leadScore >= 0
);

const items = $input.all();
const GEO = ['us','usa','united states','uk','london','canada','australia','india','new york','san francisco','los angeles','toronto','mumbai','bangalore','dubai','singapore','berlin','amsterdam'];
const T1 = ['ai','automation','agency','saas'];
const T2 = ['marketing','growth','tech','startup','consultant','founder','ceo','chatgpt','gpt','openai','n8n','zapier'];
const T3 = ['digital','freelance','business','entrepreneur','coach','strategist'];

return items.map(item => {
  const d = item.json;
  const fc = d.author?.followers || d.followersCount || 0;
  const likes = d.likeCount || d.likes || 0;
  const rts = d.retweetCount || d.retweets || 0;
  const er = fc > 0 ? (likes + rts) / fc : 0;
  const bio = (d.author?.description || d.bio || '').toLowerCase();
  const loc = (d.author?.location || d.location || bio).toLowerCase();

  let fs = 0;
  if (fc >= 200 && fc < 1000) fs = 10;
  else if (fc >= 1000 && fc < 5000) fs = 22;
  else if (fc >= 5000 && fc < 20000) fs = 30;
  else if (fc >= 20000 && fc < 50000) fs = 25;
  else if (fc >= 50000 && fc <= 100000) fs = 15;

  const es = Math.min(Math.round(er * 1000), 30);
  const bs = Math.min(
    T1.filter(k => bio.includes(k)).length * 10 +
    T2.filter(k => bio.includes(k)).length * 5 +
    T3.filter(k => bio.includes(k)).length * 3,
    40
  );
  const geo = GEO.some(g => loc.includes(g));
  const score = Math.min(fs + es + bs + (geo ? 5 : 0), 100);

  return {
    json: {
      platform: 'twitter',
