for (const item of $input.all()) {
  const key = item.json.platform + ':' + item.json.username;
  if (seen.has(key)) continue;
  seen.add(key);
  if (item.json.platform === 'instagram') ig.push(item);
  else x.push(item);
}
const sort = arr => arr.sort((a, b) => b.json.leadScore - a.json.leadScore);
const result = [...sort(ig).slice(0, 100), ...sort(x).slice(0, 100)];
